//-------------------------------------------------------------------------
// 거래명세서 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCertiList = async function () {
  // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
  var rs = await $c.gus.cfValidate($p, [ica_pchsIntendDtSt, ica_pchsIntendDtEnd, ed_pchsDeptCd]);
  if (!rs) {
    return;
  }
  rs = await $c.gus.cfIsAfterDate($p, ica_pchsIntendDtSt.getValue(), ica_pchsIntendDtEnd.getValue());
  if (!rs) {
    await $c.gus.cfAlertMsg($p, "조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
    ica_pchsIntendDtSt.focus();
    return;
  }
  $c.sbm.execute($p, sbm_searchCertiList);
};

