//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList = new Array(); // 공통POP-UP -> 요청화면 
  var pWhere = "";
  var pWtitleSearch = "";
  switch (disGubun) {
    case 1:
      // 매입거래처 팝업         
      udc_pchsClnt.setSelectId('retrieveClntList');
      udc_pchsClnt.cfCommonPopUp(scwin.udc_pchsClnt_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 2:
      // 매입부서 팝업          
      udc_pchsDept.setSelectId('retrieveLobranInfo');
      udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 3:
      // 승인담당자 팝업         
      udc_admitPic.setSelectId('retrieveEmpInfo');
      udc_admitPic.cfCommonPopUp(scwin.udc_admitPic_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 4:
      // udc_adjmDept
      // 정산부서 팝업          
      udc_adjmDept.setSelectId('retrieveLobranInfo');
      udc_adjmDept.cfCommonPopUp(scwin.udc_adjmDept_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 5:
      // udc_drawEmp
      // 작성자 팝업           
      udc_drawEmp.setSelectId('retrieveEmpInfo');
      udc_drawEmp.cfCommonPopUp(scwin.udc_drawEmp_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      break;
    case 6:
      // udc_drawAcctDept
      // 작성귀속부서 팝업
      var param_y = ica_slipDt.getValue().trim(); //예산년도 파람메터추가 ejsong9
      udc_drawAcctDept.setSelectId('retrieveAcctDeptCdInfo');
      udc_drawAcctDept.cfCommonPopUp(scwin.udc_drawAcctDept_callBackFunc, pCode.trim(), pName, pClose, null, null, null, null, param_y, ",,0", "410", null, null, null);
      break;
    default:
      break;
  }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!(await $c.gus.cfCanOpenPopup($p, inObj, pairObj))) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  // inObj가 코드명 필드일 경우 팝업
  else scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

