//  가지급금,선급금 정리화면
//-------------------------------------------------------------------------
scwin.f_Prepay = async function () {
  var valueObject = new Object();
  valueObject.prov = ds_prov;
  valueObject.provHeader = ds_provHeader;
  valueObject.txtrltSeq = "1";
  valueObject.adjmClsCd = "4"; //4^가지급금
  valueObject.sum = scwin.suspensePaySum;
  valueObject.crcCd = "KRW"; //원화
  valueObject.acctDeptCd = $c.data.getMemInfo($p, "acctDeptCd");
  valueObject.acctDeptNm = $c.data.getMemInfo($p, "acctDeptNm");
  for (j = 0; j < ds_provHeader.getRowCount(); j++) {
    if (ds_provHeader.getCellData(j, "reqAcctDeptCd") != "") {
      valueObject.acctDeptCd = ds_provHeader.getCellData(j, "reqAcctDeptCd");
      valueObject.acctDeptNm = ds_provHeader.getCellData(j, "reqAcctDeptNm");
    }
  }
  if (typeof valueObject.acctDeptCd == "undefined" || valueObject.acctDeptCd == "") {
    valueObject.acctDeptCd = "";
    valueObject.acctDeptNm = "";
  }

  // var style = "center:yes; dialogwidth:1000px; dialogheight:520px; scroll:no; resizable:no; status:yes;";
  // var strPath = "/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.jsp?
  // compare=1
  // &flag=Y
  // &gubun=1
  // &slipDt="+ed_slipDt.text.trim();
  // let win_url = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.xml";
  // let opts = {
  //     id : "ediCallPop"
  //     , popupName : ""
  //     , modal : true
  //     , type : "browserPopup"
  //     , width : 840
  //     , height : 400
  //     , title : ""
  // };

  // // 가지급금입금 호출 
  let data = {
    prov: valueObject.prov,
    provHeader: valueObject.provHeader,
    txtrltSeq: valueObject.txtrltSeq,
    adjmClsCd: valueObject.adjmClsCd,
    sum: valueObject.sum,
    crcCd: valueObject.crcCd,
    acctDeptCd: valueObject.acctDeptCd,
    acctDeptNm: valueObject.acctDeptNm,
    compare: 1,
    flag: "Y",
    gubun: 1,
    slipDt: ica_slipDt.getValue().trim()
  };
  let win_url = "/ui/ac/fi/gnrlaccount/slipmgnt/fi_201_02_02b.xml";
  let opts = {
    id: "smpPop",
    popupName: "가지급금입금",
    modal: true,
    type: "browserPopup",
    width: 1400,
    height: 760,
    title: "가지급금입금"
  };
  var returnValue = await $c.win.openPopup($p, win_url, opts, data);
  if (returnValue != null) {
    // ds_prov.ImportData(returnValue.prov);
    // ds_provHeader.ImportData(returnValue.provHeader);
    // ds_prov.SortExpr= "+rltSeq +slipNo";
    // ds_prov.Sort();

    ds_prov.setJSON(returnValue.prov);
    ds_provHeader.setJSON(returnValue.provHeader);
    var options = {
      sortIndex: "rltSeq slipNo",
      sortOrder: "1 1"
    };
    ds_prov.multisort(options);
    // 중복된것 삭제
    for (i = 0; i < ds_prov.getRowCount() - 1; i++) {
      for (j = i + 1; j < ds_prov.getRowCount(); j++) {
        if (ds_prov.getCellData(i, "rltSeq") == ds_prov.getCellData(j, "rltSeq")) {
          if (ds_prov.getCellData(i, "slipNo") == ds_prov.getCellData(j, "slipNo")) {
            ds_prov.deleteRow(i);
            break;
          }
        }
      }
    }
    for (i = 0; i < ds_provHeader.getRowCount() - 1; i++) {
      for (j = i + 1; j <= ds_provHeader.getRowCount(); j++) {
        if (ds_provHeader.getCellData(i, "rltSeq") == ds_provHeader.getCellData(j, "rltSeq")) {
          ds_provHeader.deleteRow(i);
          break;
        }
      }
    } // for end
  }
  for (i = 0; i < ds_prov.getRowCount(); i++) {
    ds_prov.getCellData(i, "setlDt", ds_provHeader.getCellData(0, "setlDt"));
  }
};

// 일괄적용함수
scwin.f_PchsInfoApply = async function () {
  var cnt = 0;
  if (ds_certiList.getRowCount() <= 0) {
    await $c.win.alert($p, "자료가 존재하지 않습니다.");
    return false;
  }
  for (var i = 0; i < ds_certiList.getRowCount(); i++) {
    if (ds_certiList.getCellData(i, "chk") == "T") {
      var slipNo = ds_certiList.getCellData(i, "slipNo");
      if (slipNo != "") {
        await $c.gus.cfAlertMsg($p, "이미 접수된 건이 포함되어 있습니다.");
        return;
      }
      cnt++;
    }
  }
  if (cnt == 0) {
    await $c.win.alert($p, "체크된 데이터가 없습니다. 적용하려는 Row의 첫 열의 체크박스를 선택해 주십시오.");
    return false;
  }
  var rs = await $c.win.confirm($p, "체크된 " + cnt + "건에 대해 매입정보 일괄 적용하시겠습니까?");
  if (rs) {
    for (var i = 0; i < ds_certiList.getRowCount(); i++) {
      if (ds_certiList.getCellData(i, "chk") == "T") {
        ds_certiList.setCellData(i, "adjmDept", ed_adjmDeptCd.getValue());
        ds_certiList.setCellData(i, "adjmDeptNm", ed_adjmDeptNm.getValue());
        ds_certiList.setCellData(i, "slipDt", ica_slipDt.getValue());
        ds_certiList.setCellData(i, "evidKndClsCd", acb_evidKndClsCd.getValue());
        ds_certiList.setCellData(i, "taxnClsCd", acb_taxnClsCd.getValue());
        ds_certiList.setCellData(i, "summary", ed_summary.getValue());
        ds_certiList.setCellData(i, "drawEmpNo", ed_drawEmpNo.getValue());
        ds_certiList.setCellData(i, "drawEmpNm", ed_drawEmpNm.getValue());
        ds_certiList.setCellData(i, "drawAcctDeptCd", ed_drawAcctDeptCd.getValue());
        ds_certiList.setCellData(i, "drawAcctDeptNm", ed_drawAcctDeptNm.getValue());
        ds_certiList.setCellData(i, "payDt", ica_payDt.getValue());
        ds_certiList.setCellData(i, "reqPayMthdCd", acb_reqPayMthdCd.getValue());
        ds_certiList.setCellData(i, "spplyDt", ica_spplyDt.getValue());
      }
    }
  }
};
