scwin.gr_certiList_oncellclick = async function (row, columnIndex, colid) {
  scwin.selectRow = row;
  // if (row == 0) return;
  if (colid == "chk" && ds_certiList.getCellData(row, "slipNo") != "") {
    await $c.win.alert($p, "전표생성된 건은 선택할 수 없습니다.");
    ds_certiList.setCellData(row, "chk", "F");
    return;
  }
  if (ds_certiList.getCellData(row, "slipNo") != "") {
    gr_certiList.setCellReadOnly(row, 'adjmDept', true);
    gr_certiList.setCellReadOnly(row, 'slipDt', true);
    gr_certiList.setCellReadOnly(row, 'taxnClsCd', true);
    gr_certiList.setCellReadOnly(row, 'summary', true);
    gr_certiList.setCellReadOnly(row, 'drawEmpNo', true);
    gr_certiList.setCellReadOnly(row, 'drawAcctDeptCd', true);
    gr_certiList.setCellReadOnly(row, 'spplyDt', true);
    // gr_certiList.setCellReadOnly(row, 'elecAuthTrgtYn',true);
    gr_certiList.setCellReadOnly(row, 'reqPayMthdCd', true);
    gr_certiList.setCellReadOnly(row, 'payDt', true);
    gr_certiList.setCellReadOnly(row, 'bfPayDt', true);
  } else {
    gr_certiList.setCellReadOnly(row, 'adjmDept', false);
    gr_certiList.setCellReadOnly(row, 'slipDt', false);
    gr_certiList.setCellReadOnly(row, 'evidKndClsCd', false);
    gr_certiList.setCellReadOnly(row, 'taxnClsCd', false);
    gr_certiList.setCellReadOnly(row, 'summary', false);
    gr_certiList.setCellReadOnly(row, 'drawEmpNo', false);
    gr_certiList.setCellReadOnly(row, 'drawAcctDeptCd', false);
    gr_certiList.setCellReadOnly(row, 'spplyDt', false);
    // gr_certiList.setCellReadOnly(row, 'elecAuthTrgtYn',false);
    gr_certiList.setCellReadOnly(row, 'reqPayMthdCd', false);
    gr_certiList.setCellReadOnly(row, 'payDt', false);
    gr_certiList.setCellReadOnly(row, 'bfPayDt', false);
  }

  // 세금계산서 접수 등록 상세 조회    
  if (colid == "slipNo") {
    if (ds_certiList.getCellData(row, "slipNo") != "") await scwin.f_RetrievePurchaseEvidence(row);
  }

  // 거래영세서 출력
  if (colid == "recptYn" && ds_certiList.getCellData(row, "recptYn") == "Y") {
    await scwin.f_PrintSlipNo(ds_certiList.getCellData(row, "slipNo"));
  }
};
